                <span className="font-mono text-xs uppercase tracking-[0.3em] text-[#FF9500] font-light">
                  Portfolio Intelligence
                </span>
              </div>
            </div>

            {/* Main Heading - The Masterpiece */}
            <div className={`transition-all duration-1200 delay-200 ${isLoaded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}`}>
              <h1 className="relative mb-8">
                {/* Background glow effect */}
