                    <span 
                      className="inline-block bg-gradient-to-r from-[#FF9500] via-[#FFB84D] to-[#FF9500] bg-clip-text text-transparent bg-size-200 animate-[gradient-shift_3s_ease-in-out_infinite]"
                      style={{ 
                        backgroundSize: '200% 200%',
                        textShadow: '0 0 60px rgba(255, 149, 0, 0.2)'
                      }}
                      key={currentWord}
                    >
                      {rotatingWords[currentWord]}.
                    </span>
                  </div>
                </div>
              </h1>

              {/* Subheading - Reduced size */}
              <div className="relative mb-12">
                <h2 className="font-dm subheading-premium text-premium text-lg md:text-xl lg:text-2xl text-gray-300 max-w-full md:max-w-[95%]">
                  Most investors{" "}
                  <span className="relative">
                    <span className="font-light text-white">never notice</span>
                    <div className="absolute bottom-0 left-0 w-full h-px bg-gradient-to-r from-[#FF9500]/40 to-transparent"></div>
                  </span>
                  {" "}the silent wealth erosion.
                </h2>
              </div>
            </div>

            {/* Description - Reduced size */}
            <div className={`transition-all duration-1000 delay-400 ${isLoaded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
              <p className="font-dm text-premium text-base md:text-lg text-gray-400 max-w-full md:max-w-[90%] leading-relaxed mb-14 font-extralight">
                Real-time drift detection, threshold alerts, and one-click rebalancing ??? 
                <span className="text-gray-300 font-light"> built for investors who take allocation seriously.</span>
              </p>
            </div>

            {/* CTA Section - Sleek and minimal */}
            <div className={`transition-all duration-1000 delay-600 ${isLoaded ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4'}`}>
              <div className="flex flex-col sm:flex-row items-start sm:items-center gap-10">
                <Link
                  to={ctaHref}
                  className="group relative inline-flex items-center justify-center bg-gradient-to-r from-[#FF9500] to-[#FFB84D] text-black font-dm font-medium text-base px-8 py-4 rounded-xl hover:shadow-[0_0_40px_rgba(255,149,0,0.3)] transition-all duration-700 transform hover:scale-[1.02] active:scale-[0.98] overflow-hidden"
                >
                  {/* Subtle shimmer effect */}
                  <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent transform translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1200"></div>

                  <span className="relative flex items-center gap-3 text-premium font-light">
                    {user ? "Go to Dashboard" : "Start Free Trial"}
                    <svg className="w-4 h-4 transform group-hover:translate-x-1 transition-transform duration-500" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={1.5}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M17 8l4 4m0 0l-4 4m4-4H3" />
                    </svg>
                  </span>
                </Link>

                <div className="flex flex-col gap-3">
                  <div className="flex items-center gap-4 text-gray-400 text-sm font-dm text-premium font-extralight">
                    <svg className="w-4 h-4 text-green-400" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                    </svg>
                    <span>No credit card required</span>
                  </div>
                  <div className="flex items-center gap-4 text-gray-400 text-sm font-dm text-premium font-extralight">
                    <svg className="w-4 h-4 text-green-400" fill="currentColor" viewBox="0 0 20 20">
                      <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                    </svg>
                    <span>Setup in under 2 minutes</span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Status HUD - Repositioned to avoid overlap */}
      <div className={`hidden lg:block absolute top-8 right-8 transition-all duration-1000 delay-800 ${isLoaded ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4'}`}>
        <div className="backdrop-blur-3xl bg-white/[0.02] border border-white/5 rounded-2xl p-6 shadow-2xl min-w-[260px]">
          <div className="flex items-center gap-3 mb-4">
            <div className="relative">
              <div className="w-2 h-2 bg-[#FF9500] rounded-full animate-pulse"></div>
              <div className="absolute inset-0 w-2 h-2 bg-[#FF9500] rounded-full animate-ping opacity-50"></div>
            </div>
            <span className="text-white text-xs font-dm font-extralight">Global Market Intelligence</span>
